/**
 * Re-exports the Procertus categorization module. Use `src/categorization.ts` (not a folder) so
 * Vite’s `workspaceUiAliasPlugin` can resolve `@/categorization` to a single file.
 * Runtime document: `ProcertusCategorizationProvider` in `main.tsx`.
 */
export * from "@procertus-ui/procertus-categorization";

import { useCallback, useMemo, useState } from "react";

export type UseOnboardingFlowShellOptions = {
  totalSteps: number;
  initialStep?: number;
  /**
   * Whether the user may leave the current step for the next one. Implement
   * prerequisites per step (forms valid, consents, selections) here.
   */
  canAdvanceFrom?: (activeStep: number) => boolean;
};

export function useOnboardingFlowShell({
  totalSteps: totalStepsIn,
  initialStep = 0,
  canAdvanceFrom = () => true,
}: UseOnboardingFlowShellOptions) {
  const totalSteps = Math.max(1, Math.floor(totalStepsIn));

  const [activeStep, setActiveStep] = useState(() => {
    const c = Math.min(Math.max(0, initialStep), totalSteps - 1);
    return c;
  });

  const isFirst = activeStep <= 0;
  const isLast = activeStep >= totalSteps - 1;

  const canGoBack = !isFirst;

  const canGoForward = useMemo(
    () => !isLast && canAdvanceFrom(activeStep),
    [isLast, activeStep, canAdvanceFrom],
  );

  const goBack = useCallback(() => {
    setActiveStep((s) => (s > 0 ? s - 1 : s));
  }, []);

  const goForward = useCallback(() => {
    setActiveStep((s) => {
      if (s >= totalSteps - 1) return s;
      if (!canAdvanceFrom(s)) return s;
      return s + 1;
    });
  }, [totalSteps, canAdvanceFrom]);

  const goToStep = useCallback(
    (step: number) => {
      const next = Math.min(Math.max(0, Math.floor(step)), totalSteps - 1);
      setActiveStep(next);
    },
    [totalSteps],
  );

  return {
    activeStep,
    totalSteps,
    isFirst,
    isLast,
    canGoBack,
    canGoForward,
    goBack,
    goForward,
    goToStep,
  };
}

/**
 * Onboarding / wizard **step page** chrome: header (title, optional description, step
 * label), body slot, footer (back, optional secondary, primary). Presentational
 * only — drive navigation and “can go next?” with {@link useOnboardingFlowShell}
 * and pass the resulting flags and handlers in as props.
 *
 * **Heading:** one `h1` for the step title. Do not place interactive controls inside
 * the heading. Align spacing and type with the Documentation Portal guidelines.
 */
import type { ReactNode } from "react";

import { cn } from "@/lib/utils";
import { Button, Card, CardContent, CardFooter, CardHeader, Separator } from "@procertus-ui/ui";
import { P } from "@procertus-ui/ui";

export type FlowShellAction = {
  label: string;
  onClick: () => void;
  disabled?: boolean;
  loading?: boolean;
};

export type OnboardingFlowShellProps = {
  className?: string;
  /**
   * Step chrome density: wider, calmer “onboarding” reading width vs compact “wizard”.
   */
  variant?: "onboarding" | "wizard";
  title: ReactNode;
  description?: ReactNode;
  /** e.g. “Step 2 of 6” — not a second heading. */
  stepLabel?: string;
  children?: ReactNode;
  /** Shown on the left in LTR; omit on the first step. */
  backAction?: FlowShellAction;
  primaryAction: FlowShellAction;
  secondaryAction?: FlowShellAction;
};

const variantClass: Record<NonNullable<OnboardingFlowShellProps["variant"]>, string> = {
  onboarding: "max-w-2xl",
  wizard: "max-w-xl",
};

const headerClass: Record<NonNullable<OnboardingFlowShellProps["variant"]>, string> = {
  onboarding: "gap-2 pt-2",
  wizard: "gap-1.5 py-1",
};

const titleClass: Record<NonNullable<OnboardingFlowShellProps["variant"]>, string> = {
  onboarding: "text-2xl font-semibold tracking-tight",
  wizard: "text-xl font-semibold tracking-tight",
};

const descClass: Record<NonNullable<OnboardingFlowShellProps["variant"]>, string> = {
  onboarding: "text-base",
  wizard: "text-sm",
};

const contentClass: Record<NonNullable<OnboardingFlowShellProps["variant"]>, string> = {
  onboarding: "space-y-4 pt-6",
  wizard: "space-y-3 py-4 pt-4",
};

export function OnboardingFlowShell({
  className,
  variant = "onboarding",
  title,
  description,
  stepLabel,
  children,
  backAction,
  primaryAction,
  secondaryAction,
}: OnboardingFlowShellProps) {
  return (
    <Card
      className={cn("mx-auto w-full overflow-hidden shadow-sm", variantClass[variant], className)}
    >
      <CardHeader className={headerClass[variant]}>
        {stepLabel ? (
          <p className="text-sm text-muted-foreground" aria-hidden={false}>
            {stepLabel}
          </p>
        ) : null}
        <h1 className={titleClass[variant]}>{title}</h1>
        {description ? (
          typeof description === "string" ? (
            <P className={cn("text-muted-foreground", descClass[variant])}>{description}</P>
          ) : (
            <div className={cn("text-muted-foreground", descClass[variant])}>{description}</div>
          )
        ) : null}
      </CardHeader>
      <Separator />
      <CardContent className={contentClass[variant]}>{children}</CardContent>
      <CardFooter
        className={cn(
          "flex flex-col gap-3 border-t bg-muted/20 sm:flex-row sm:items-center sm:justify-between",
          variant === "wizard" ? "py-3" : "py-4",
        )}
      >
        <div className="flex w-full min-h-10 sm:w-auto">
          {backAction ? (
            <Button
              type="button"
              variant="outline"
              disabled={backAction.disabled}
              onClick={backAction.onClick}
            >
              {backAction.label}
            </Button>
          ) : (
            <span className="hidden sm:block sm:min-w-0" aria-hidden />
          )}
        </div>
        <div className="flex w-full flex-wrap justify-end gap-2 sm:w-auto">
          {secondaryAction ? (
            <Button
              type="button"
              variant="secondary"
              disabled={secondaryAction.disabled}
              onClick={secondaryAction.onClick}
            >
              {secondaryAction.label}
            </Button>
          ) : null}
          <Button
            type="button"
            disabled={primaryAction.disabled}
            onClick={primaryAction.onClick}
            aria-busy={primaryAction.loading}
          >
            {primaryAction.loading ? "…" : primaryAction.label}
          </Button>
        </div>
      </CardFooter>
    </Card>
  );
}

